        let dec_arr = arr_impl.inner.as_any()
            .downcast_ref::<arrow_array::Decimal128Array>()
            .ok_or_else(|| arrays::ArrowError::InvalidArgument("Not a Decimal128 array".to_string()))?;
        let value = dec_arr.value(index as usize);
